import { useState, useEffect, useRef } from 'react';
import {
  FiUpload,
  FiImage,
  FiTrash2,
  FiChevronLeft,
  FiChevronRight,
  FiX,
  FiLink,
} from 'react-icons/fi';

import {
  getMyProducts,
  createProduct,
  updateProduct,
  deleteProduct,
} from '../services/api';

import { useAuth } from '../context/AuthContext';
import { toast } from 'react-toastify';

const EMPTY_FORM = {
  name: '',
  description: '',
  price: '',
  discountPrice: '',
  category: '',
  stock: '',
  brand: '',
  images: [],
};

const SellerDashboard = () => {
  const [products, setProducts] = useState([]);
  const [tab, setTab] = useState('products');
  const [form, setForm] = useState(EMPTY_FORM);
  const [editId, setEditId] = useState(null);

  const [previews, setPreviews] = useState([]);

  const [uploading, setUploading] = useState(false);
  const [dragging, setDragging] = useState(false);

  const [urlInput, setUrlInput] = useState('');
  const [showUrl, setShowUrl] = useState(false);

  const fileInputRef = useRef(null);

  const { user } = useAuth();

  const BACKEND_URL = 'http://localhost:5000';

  // ─────────────────────────────────────────────
  // IMAGE URL
  // ─────────────────────────────────────────────

  const getImageUrl = (image) => {
    if (!image) return '';

    if (
      typeof image === 'string' &&
      (image.startsWith('http') ||
        image.startsWith('blob:'))
    ) {
      return image;
    }

    if (typeof image === 'string') {
      const cleanPath = image.replace(/^\/+/, '');

      return `${BACKEND_URL}/${cleanPath}`;
    }

    return '';
  };

  // ─────────────────────────────────────────────
  // LOAD PRODUCTS
  // ─────────────────────────────────────────────

  const load = async () => {
    try {
      const res = await getMyProducts();

      setProducts(res.data.products);
    } catch (err) {
      toast.error('Failed to load products');
    }
  };

  useEffect(() => {
    load();
  }, []);

  // ─────────────────────────────────────────────
  // PROCESS FILES
  // ─────────────────────────────────────────────

  const processFiles = (files) => {
    const imageFiles = Array.from(files).filter(
      (f) => f.type.startsWith('image/')
    );

    if (!imageFiles.length) return;

    imageFiles.forEach((file) => {
      if (file.size > 5 * 1024 * 1024) {
        toast.error(
          `${file.name} exceeds 5MB`
        );

        return;
      }

      const previewUrl =
        URL.createObjectURL(file);

      setPreviews((prev) => [
        ...prev,
        {
          file,
          url: previewUrl,
        },
      ]);

      setForm((prev) => ({
        ...prev,
        images: [...prev.images, file],
      }));
    });
  };

  const onFileInput = (e) => {
    processFiles(e.target.files);

    e.target.value = '';
  };

  const onDrop = (e) => {
    e.preventDefault();

    setDragging(false);

    processFiles(e.dataTransfer.files);
  };

  // ─────────────────────────────────────────────
  // IMAGE URL ADD
  // ─────────────────────────────────────────────

  const addImageUrl = () => {
    const url = urlInput.trim();

    if (!url) return;

    if (!url.startsWith('http')) {
      toast.error('Invalid URL');

      return;
    }

    setPreviews((prev) => [
      ...prev,
      {
        file: null,
        url,
      },
    ]);

    setForm((prev) => ({
      ...prev,
      images: [...prev.images, url],
    }));

    setUrlInput('');
    setShowUrl(false);
  };

  // ─────────────────────────────────────────────
  // REMOVE IMAGE
  // ─────────────────────────────────────────────

  const removeImage = (index) => {
    setForm((prev) => ({
      ...prev,
      images: prev.images.filter(
        (_, i) => i !== index
      ),
    }));

    setPreviews((prev) =>
      prev.filter((_, i) => i !== index)
    );
  };

  // ─────────────────────────────────────────────
  // MOVE IMAGE
  // ─────────────────────────────────────────────

  const moveImage = (index, dir) => {
    const newIndex = index + dir;

    if (
      newIndex < 0 ||
      newIndex >= form.images.length
    ) {
      return;
    }

    const newImages = [...form.images];
    const newPreviews = [...previews];

    [newImages[index], newImages[newIndex]] =
      [
        newImages[newIndex],
        newImages[index],
      ];

    [
      newPreviews[index],
      newPreviews[newIndex],
    ] = [
      newPreviews[newIndex],
      newPreviews[index],
    ];

    setForm((prev) => ({
      ...prev,
      images: newImages,
    }));

    setPreviews(newPreviews);
  };

  // ─────────────────────────────────────────────
  // RESET
  // ─────────────────────────────────────────────

  const resetForm = () => {
    setForm(EMPTY_FORM);

    setPreviews([]);

    setEditId(null);

    setUrlInput('');

    setShowUrl(false);
  };

  // ─────────────────────────────────────────────
  // EDIT
  // ─────────────────────────────────────────────

  const handleEdit = (p) => {
    setForm({
      name: p.name,
      description: p.description,
      price: p.price,
      discountPrice:
        p.discountPrice || '',
      category: p.category,
      stock: p.stock,
      brand: p.brand || '',
      images: p.images || [],
    });

    setPreviews(
      (p.images || []).map((img) => ({
        file: null,
        url: getImageUrl(img),
      }))
    );

    setEditId(p._id);

    setTab('add');
  };

  // ─────────────────────────────────────────────
  // DELETE
  // ─────────────────────────────────────────────

  const handleDelete = async (id) => {
    if (
      !window.confirm(
        'Delete this product?'
      )
    ) {
      return;
    }

    try {
      await deleteProduct(id);

      toast.success('Deleted');

      load();
    } catch (err) {
      toast.error('Delete failed');
    }
  };

  // ─────────────────────────────────────────────
  // SUBMIT
  // ─────────────────────────────────────────────

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (form.images.length === 0) {
      toast.error(
        'Please add at least one image'
      );

      return;
    }

    setUploading(true);

    try {
      const formData = new FormData();

      formData.append(
        'name',
        form.name
      );

      formData.append(
        'description',
        form.description
      );

      formData.append(
        'price',
        form.price
      );

      formData.append(
        'discountPrice',
        form.discountPrice
      );

      formData.append(
        'category',
        form.category
      );

      formData.append(
        'stock',
        form.stock
      );

      formData.append(
        'brand',
        form.brand
      );

      form.images.forEach((img) => {
        if (img instanceof File) {
          formData.append(
            'images',
            img
          );
        } else {
          formData.append(
            'existingImages',
            img
          );
        }
      });

      if (editId) {
        await updateProduct(
          editId,
          formData
        );

        toast.success(
          'Product updated'
        );
      } else {
        await createProduct(formData);

        toast.success(
          'Product submitted'
        );
      }

      resetForm();

      setTab('products');

      load();
    } catch (err) {
      toast.error(
        err.response?.data?.message ||
          'Something went wrong'
      );
    } finally {
      setUploading(false);
    }
  };

  // ─────────────────────────────────────────────
  // UI
  // ─────────────────────────────────────────────

  return (
    <div className="admin-page">
      <h1>Seller Dashboard</h1>

      <div className="admin-tabs">
        <button
          className={
            tab === 'products'
              ? 'active'
              : ''
          }
          onClick={() =>
            setTab('products')
          }
        >
          My Products
        </button>

        <button
          className={
            tab === 'add'
              ? 'active'
              : ''
          }
          onClick={() => {
            resetForm();

            setTab('add');
          }}
        >
          + Add Product
        </button>
      </div>

      {/* PRODUCTS */}

      {tab === 'products' && (
        <table className="admin-table">
          <thead>
            <tr>
              <th>Image</th>
              <th>Name</th>
              <th>Price</th>
              <th>Stock</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>

          <tbody>
            {products.map((p) => (
              <tr key={p._id}>
                <td>
                  {p.images?.[0] ? (
                    <img
                      src={getImageUrl(
                        p.images[0]
                      )}
                      alt={p.name}
                      style={{
                        width: 50,
                        height: 60,
                        objectFit: 'cover',
                        borderRadius: 4,
                      }}
                    />
                  ) : (
                    <div
                      style={{
                        width: 50,
                        height: 60,
                        display: 'flex',
                        alignItems:
                          'center',
                        justifyContent:
                          'center',
                        background:
                          '#f2f2f2',
                      }}
                    >
                      <FiImage />
                    </div>
                  )}
                </td>

                <td>{p.name}</td>

                <td>
                  PKR {p.price}
                </td>

                <td>{p.stock}</td>

                <td>
                  <span
                    className={
                      p.isApproved
                        ? 'badge-green'
                        : 'badge-yellow'
                    }
                  >
                    {p.isApproved
                      ? 'Approved'
                      : 'Pending'}
                  </span>
                </td>

                <td>
                  <button
                    className="btn-sm"
                    onClick={() =>
                      handleEdit(p)
                    }
                  >
                    Edit
                  </button>

                  <button
                    className="btn-sm btn-danger"
                    onClick={() =>
                      handleDelete(
                        p._id
                      )
                    }
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {/* FORM */}

      {tab === 'add' && (
        <form
          className="product-form"
          onSubmit={handleSubmit}
        >
          <h2>
            {editId
              ? 'Edit Product'
              : 'Add Product'}
          </h2>

          {[
            'name',
            'brand',
            'category',
          ].map((field) => (
            <input
              key={field}
              placeholder={
                field
                  .charAt(0)
                  .toUpperCase() +
                field.slice(1)
              }
              value={form[field]}
              onChange={(e) =>
                setForm((prev) => ({
                  ...prev,
                  [field]:
                    e.target.value,
                }))
              }
              required={
                field !== 'brand'
              }
            />
          ))}

          <textarea
            rows={4}
            placeholder="Description"
            value={form.description}
            onChange={(e) =>
              setForm((prev) => ({
                ...prev,
                description:
                  e.target.value,
              }))
            }
            required
          />

          <div className="form-row">
            <input
              type="number"
              placeholder="Price"
              value={form.price}
              onChange={(e) =>
                setForm((prev) => ({
                  ...prev,
                  price:
                    e.target.value,
                }))
              }
              required
            />

            <input
              type="number"
              placeholder="Discount Price"
              value={
                form.discountPrice
              }
              onChange={(e) =>
                setForm((prev) => ({
                  ...prev,
                  discountPrice:
                    e.target.value,
                }))
              }
            />

            <input
              type="number"
              placeholder="Stock"
              value={form.stock}
              onChange={(e) =>
                setForm((prev) => ({
                  ...prev,
                  stock:
                    e.target.value,
                }))
              }
              required
            />
          </div>

          {/* IMAGE AREA */}

          <div
            style={{
              marginTop: '1rem',
            }}
          >
            <label
              style={{
                display: 'block',
                marginBottom:
                  '0.6rem',
                fontWeight: 600,
              }}
            >
              Product Images
            </label>

            <div
              onDragEnter={(e) => {
                e.preventDefault();

                setDragging(true);
              }}
              onDragOver={(e) => {
                e.preventDefault();

                setDragging(true);
              }}
              onDragLeave={(e) => {
                e.preventDefault();

                setDragging(false);
              }}
              onDrop={onDrop}
              onClick={() =>
                fileInputRef.current?.click()
              }
              style={{
                border: `2px dashed ${
                  dragging
                    ? '#c47878'
                    : '#e4cfa0'
                }`,
                padding: '1.5rem',
                borderRadius: 8,
                cursor: 'pointer',
                textAlign: 'center',
              }}
            >
              <input
                type="file"
                multiple
                accept="image/*"
                ref={fileInputRef}
                style={{
                  display: 'none',
                }}
                onChange={
                  onFileInput
                }
              />

              <div
                style={{
                  fontSize:
                    '2rem',
                  marginBottom:
                    '0.7rem',
                }}
              >
                {dragging ? (
                  <FiUpload />
                ) : (
                  <FiImage />
                )}
              </div>

              <p>
                Drag & Drop Images
              </p>

              <button
                type="button"
                style={{
                  marginTop:
                    '0.8rem',
                  pointerEvents:
                    'none',
                }}
              >
                Attach Files
              </button>
            </div>

            {/* URL */}

            {!showUrl ? (
              <button
                type="button"
                onClick={() =>
                  setShowUrl(true)
                }
                style={{
                  marginTop:
                    '0.8rem',
                }}
              >
                <FiLink /> Add by
                URL
              </button>
            ) : (
              <div
                style={{
                  display: 'flex',
                  gap: 8,
                  marginTop:
                    '0.8rem',
                }}
              >
                <input
                  type="url"
                  value={urlInput}
                  placeholder="https://example.com/image.jpg"
                  onChange={(e) =>
                    setUrlInput(
                      e.target.value
                    )
                  }
                  style={{
                    flex: 1,
                  }}
                />

                <button
                  type="button"
                  onClick={
                    addImageUrl
                  }
                >
                  Add
                </button>

                <button
                  type="button"
                  onClick={() => {
                    setShowUrl(
                      false
                    );

                    setUrlInput('');
                  }}
                >
                  <FiX />
                </button>
              </div>
            )}

            {/* PREVIEWS */}

            {previews.length > 0 && (
              <div
                style={{
                  display: 'grid',
                  gridTemplateColumns:
                    'repeat(auto-fill,minmax(90px,1fr))',
                  gap: 10,
                  marginTop: '1rem',
                }}
              >
                {previews.map(
                  (img, i) => (
                    <div
                      key={i}
                      style={{
                        position:
                          'relative',
                        overflow:
                          'hidden',
                        borderRadius: 8,
                      }}
                    >
                      <img
                        src={img.url}
                        alt=""
                        style={{
                          width:
                            '100%',
                          aspectRatio:
                            '3/4',
                          objectFit:
                            'cover',
                        }}
                      />

                      <div
                        style={{
                          position:
                            'absolute',
                          inset: 0,
                          background:
                            'rgba(0,0,0,0.4)',
                          display:
                            'flex',
                          alignItems:
                            'center',
                          justifyContent:
                            'center',
                          gap: 6,
                        }}
                      >
                        {i > 0 && (
                          <button
                            type="button"
                            style={
                              iconBtnStyle
                            }
                            onClick={() =>
                              moveImage(
                                i,
                                -1
                              )
                            }
                          >
                            <FiChevronLeft />
                          </button>
                        )}

                        <button
                          type="button"
                          style={{
                            ...iconBtnStyle,
                            background:
                              'rgba(220,38,38,0.8)',
                          }}
                          onClick={() =>
                            removeImage(
                              i
                            )
                          }
                        >
                          <FiTrash2 />
                        </button>

                        {i <
                          previews.length -
                            1 && (
                          <button
                            type="button"
                            style={
                              iconBtnStyle
                            }
                            onClick={() =>
                              moveImage(
                                i,
                                1
                              )
                            }
                          >
                            <FiChevronRight />
                          </button>
                        )}
                      </div>
                    </div>
                  )
                )}
              </div>
            )}
          </div>

          {/* ACTIONS */}

          <div
            style={{
              display: 'flex',
              gap: 10,
              marginTop: '1.5rem',
            }}
          >
            <button
              type="submit"
              className="btn-primary"
              disabled={
                uploading
              }
            >
              {uploading
                ? 'Submitting...'
                : editId
                ? 'Update Product'
                : 'Submit Product'}
            </button>

            <button
              type="button"
              className="btn-ghost"
              onClick={() => {
                resetForm();

                setTab(
                  'products'
                );
              }}
            >
              Cancel
            </button>
          </div>
        </form>
      )}
    </div>
  );
};

export default SellerDashboard;

// ─────────────────────────────────────────────
// ICON BUTTON
// ─────────────────────────────────────────────

const iconBtnStyle = {
  width: 30,
  height: 30,
  borderRadius: '50%',
  border: 'none',
  background:
    'rgba(255,255,255,0.2)',
  color: '#fff',
  cursor: 'pointer',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
};
